VALUES
  ('disabled-c5fb3965-moex-00051', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '甲生向教育部陳情手機被導師保管過久，導師雖隨後發還，但旋以甲經常 遲到、上課睡覺評量德性分數不符申請獎學金資格，下列敘述何者正確？', '["甲生之德性被評量不符獎學金申請資格，甲生得提起行政爭訟", "就甲生之德性成績評量屬於導師之專業判斷，其他教師或機關應絕對尊重", "導師評量德行分數，為事實行為，不影響甲生權益，無違法問題", "甲生使用手機之權益受損屬於學生事務管理事項，不得向教育部陳情"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00052', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '下列何者為一般處分？', '["警察協助執行違章建築之拆除", "警察對人之管束", "交通號誌", "行政執行分署之催繳通知單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00053', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政機關與人民締結互負給付義務之行政契約，下列敘述何者正確？', '["契約中無須約定人民給付之特定用途", "契約之締結皆須經上級機關核准", "人民之給付無須有助於行政機關執行其職務", "行政機關收受人民之給付限於契約所載明之特定用途"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00054', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政程序法規定，下列何者非屬行政契約無效之情形？', '["受監護宣告之人民獨自簽訂契約", "主管機關與人民就行政罰鍰之金額締結契約", "個案事實與法律關係均由行政機關調查明確後，行政機關仍與人民締結 和解契約，以代替行政處分", "締約雙方均明知，與契約內容相同之行政處分，有得廢止之原因"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00055', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導與行政處分均發生法律效果", "我國行政程序法並未明文規定行政指導", "行政指導具有法律上之強制力", "行政指導相對人明確拒絕指導時，行政機關應即停止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00056', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政罰法規定，關於罰鍰裁處之審酌加減，下列敘述何者錯誤？', '["裁處罰鍰，得考量受處罰者之資力", "裁處罰鍰，應審酌違反行政法上義務行為應受責難程度、所生影響及因 違反行政法上義務所得之利益", "依行政罰法規定減輕處罰時，裁處之罰鍰原則上不得逾法定罰鍰最高額 之四分之一，亦不得低於法定罰鍰最低額之四分之一", "依行政罰法規定減輕處罰，同時有免除處罰之規定者，裁處之罰鍰原則 上不得逾法定罰鍰最高額之三分之一，亦不得低於法定罰鍰最低額之三 分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00057', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '關於行政罰之責任，下列敘述何者正確？', '["行為時因精神障礙或其他心智缺陷，致不能辨識其行為違法或欠缺依其 辨識而行為之能力者，得減輕處罰", "行為時因故意或過失自行招致精神障礙或其他心智缺陷者，不適用減輕 或不予處罰之規定", "未滿 18 歲人之行為，不予處罰；滿 18 歲以上未滿 20 歲人之行為，得 減輕處罰", "不得因不知法規而免除行政處罰責任。但按其情節，僅可減輕其處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00058', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '下列何者非屬公權力行政？', '["拆除違章建築", "課稅處分", "罰鍰處分", "機關訂購辦公設備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00059', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '甲為導遊，於帶領觀光客至風景特定區觀光時，趁機盜挖風景特定區之礦 石，為主管機關發現，移送檢察官偵查後起訴。該主管機關於下列何種情 形，不得再依發展觀光條例予以裁處罰鍰？', '["法院判決有罪確定", "法院判決無罪確定", "法院判決免訴確定", "法院判決有罪但諭知緩刑確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00060', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-114-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '某餐廳因長期違法排放大量空氣污染物，主管機關命其停止營業；該餐廳 不從，仍繼續營業。主管機關遂對之實施斷水斷電措施。此斷水斷電措施， 屬於行政執行法中何種類型之方法？', '["代履行", "直接強制", "即時強制", "間接強制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:55+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
